from vex import AuditLogger

# Initialize audit logger for HR compliance
auditor = AuditLogger(
    client=vex_client,
    policies=[
        'eeoc-guidelines',
        'nyc-local-law-144',
        'eu-ai-act-high-risk'
    ]
)

def compliance_wrapper(agent):
    def wrapped_send(recipient, message):
        audit_record = auditor.log_conversation(
            sender=agent.name,
            content=message,
            metadata={'context': 'resume_screening', 'timestamp': 'now'}
        )
        if audit_record['flagged']:
            print(f"FLAGGED: {audit_record['reason']}")
            return None
        return agent.send(recipient, message)
    agent.send = wrapped_send
    return agent

# Wrap all recruitment agents
recruiter_agent = compliance_wrapper(recruiter_agent)
screener_agent = compliance_wrapper(screener_agent)

PROTECTED_CHARACTERISTICS = [
    'race', 'color', 'religion', 'sex', 'national origin',
    'age', 'disability', 'genetic information', 'pregnancy'
]

def protected_class_filter(message):
    content = message.content.lower()
    for characteristic in PROTECTED_CHARACTERISTICS:
        if characteristic in content:
            vex_client.report_violation({
                'type': 'protected_characteristic',
                'content': message.content,
                'agents_involved': [msg.sender for msg in message.thread]
            })
            return {'action': 'block', 'reason': f"Protected characteristic '{characteristic}' mentioned"}
    return {'action': 'allow'}

# Register as pre-message filter
group_chat.register_pre_message_hook(protected_class_filter)

# Start compliant screening
result = group_chat.initiate_chat(
    recruiter_agent,
    message="Evaluate candidates for Senior Developer role"
)
